# Module defining entity classes that will be used by data_types
# Note: Using forward declaration pattern via import

class Entity:
    id: int
    label: str

    def __init__(self, id: int, label: str):
        self.id = id
        self.label = label

    @virtual
    def describe(self) -> str:
        return f"Entity {self.id}: {self.label}"

class Product(Entity):
    price: float

    def __init__(self, id: int, label: str, price: float):
        super().__init__(id, label)
        self.price = price

    @override
    def describe(self) -> str:
        return f"Product {self.id}: {self.label} at ${self.price}"

