# Utility module with helper functions and constants
from data_types import Point, Status
from entities import Entity, Product

const DEFAULT_LIMIT: int = 100

def calculate_distance(p1: Point, p2: Point) -> float:
    dx: float = p2.x - p1.x
    dy: float = p2.y - p1.y
    return (dx * dx + dy * dy) ** 0.5

def process_entity(e: Entity) -> str:
    return e.describe()

def status_to_int(s: Status) -> int:
    return s.value

def clamp_value(value: int, min_val: int, max_val: int) -> int:
    if value < min_val:
        return min_val
    if value > max_val:
        return max_val
    return value

class UtilityHelper:
    @static
    def format_status(s: Status) -> str:
        return f"Status[{s.name}]={s.value}"
